const raw = $input.item.json;
const out = {};

for (const [key, val] of Object.entries(raw)) {
  const cleanVal = typeof val === 'string' ? val.replace(/[\u0000-\u001f]+/g, ' ').trim() : val;
  out[key.trim()] = cleanVal;
}

return [{ json: out }];

const apollo = $input.item.json;
const row = $('Resolver Query Empresa').item.json;

const people = apollo.people || apollo.contacts || [];
const validTitles = /rrhh|human|people|talent|capacita|learning|desarrollo/i;
const base = (row.search_query || '').toLowerCase();

const contacts = people
  .filter(p => {
    const empresa = (p.organization_name || '').toLowerCase();
    const matchEmpresa = empresa.includes(base) || base.includes(empresa.split(' ')[0]);
    return p.email &&
      !p.email.startsWith('email_not_unlocked') &&
      validTitles.test(p.title || '') &&
      matchEmpresa;
  })
  .slice(0, 10)
  .map(p => ({
    name: [p.first_name, p.last_name].filter(Boolean).join(' ').trim(),
    title: p.title || '',
    email: p.email,
    empresa_detectada: p.organization_name || ''
  }));

const sd = $getWorkflowStaticData('global');
const empresa = row.Empresa_Nombre;

if (!sd.results) sd.results = {};
if (!sd.results[empresa]) sd.results[empresa] = [];
sd.results[empresa].push(...contacts);

if (!sd.rows) sd.rows = {};
if (!sd.rows[empresa]) sd.rows[empresa] = row;

return [{ json: {} }];

const sd = $getWorkflowStaticData('global');
const companies = sd.companiesProcessed || 0;
const contacts = sd.contactsFound || 0;

sd.companiesProcessed = 0;
sd.contactsFound = 0;

return [{
  json: {
    resumen: 'Enriquecimiento Apollo completado',
    empresas_procesadas: companies,
    contactos_encontrados: contacts,
    promedio_por_empresa: companies > 0 ? Number((contacts / companies).toFixed(2)) : 0,
    timestamp: new Date().toISOString()
  }
}];

const razon = $json.Empresa_Nombre || '';
const holding = $json.Holding || '';

function limpiar(nombre) {
  return nombre
    .replace(/(spa|ltda|s\.a\.|sa|limitada)/gi, '')
    .replace(/inversiones|sociedad|comercial|servicios/gi, '')
    .trim();
}

const base = limpiar(razon);

const queries = [
  base,
  holding,
  `${base} chile`,
  `${holding} chile`
].filter(q => q && q.length > 3);

const finalQueries = [...new Set(queries)];

return finalQueries.map(q => ({
  json: {
    ...$json,
    search_query: q
  }
}));

const sd = $getWorkflowStaticData('global');
const results = sd.results || {};
const rows = sd.rows || {};

const output = [];

for (const [empresa, contacts] of Object.entries(results)) {

  const ranked = contacts.map(c => {
    let score = 0;
    if (c.email) score += 3;
    if (/gerente|head|director/i.test(c.title)) score += 3;
    if (/rrhh|people|talent|learning/i.test(c.title)) score += 2;
    return { ...c, score };
  });

  ranked.sort((a, b) => b.score - a.score);

  const top = ranked.slice(0, 5);
  const row = rows[empresa] || { Empresa_Nombre: empresa };

  top.forEach((c, i) => {
    if (i === 0) {
      row['CONTACTO'] = c.name + ' | ' + c.title;
      row['CORREO'] = c.email;
    } else {
      row['CONTACTO ' + i] = c.name + ' | ' + c.title;
      row['CORREO' + i] = c.email;
    }
  });

  output.push({ json: row });
}

sd.results = {};
sd.rows = {};

return output;
